import { Card as CardRoot, cardVariants, type CardProps } from "./card";
import { CardAction, type CardActionProps } from "./card-action";
import { CardContent, type CardContentProps } from "./card-content";
import { CardDescription, type CardDescriptionProps } from "./card-description";
import { CardFooter, type CardFooterProps } from "./card-footer";
import { CardHeader, type CardHeaderProps } from "./card-header";
import { CardLabel, cardLabelVariants, type CardLabelProps } from "./card-label";
import { CardTitle, type CardTitleProps } from "./card-title";

const Card = Object.assign(CardRoot, {
  Action: CardAction,
  Header: CardHeader,
  Label: CardLabel,
  Title: CardTitle,
  Description: CardDescription,
  Content: CardContent,
  Footer: CardFooter,
});

export { Card, cardVariants, type CardProps };
export { CardAction, type CardActionProps };
export { CardHeader, type CardHeaderProps };
export { CardLabel, cardLabelVariants, type CardLabelProps };
export { CardTitle, type CardTitleProps };
export { CardDescription, type CardDescriptionProps };
export { CardContent, type CardContentProps };
export { CardFooter, type CardFooterProps };

import type { HTMLAttributes, Ref } from "react";
import { cva, type VariantProps } from "class-variance-authority";
import { cn } from "@/lib/utils";

export const cardVariants = cva("w-full relative border border-border bg-background", {
  variants: {
    variant: {
      default: "",
      panel: "shadow-2xl",
    },
    size: {
      default: "",
      sm: "max-w-sm",
      md: "max-w-md",
      lg: "max-w-lg",
    },
  },
  defaultVariants: { variant: "default", size: "default" },
});

export type CardProps = HTMLAttributes<HTMLElement> &
  VariantProps<typeof cardVariants> & {
    as?: "div" | "article" | "section" | "aside";
    ref?: Ref<HTMLElement>;
  };

export function Card({ className, variant, size, as: Tag = "div", ref, ...props }: CardProps) {
  return <Tag data-slot="card" ref={ref as Ref<never>} className={cn(cardVariants({ variant, size }), className)} {...props} />;
}

import type { ComponentPropsWithRef } from "react";
import { cn } from "@/lib/utils";

export type CardActionProps = ComponentPropsWithRef<"div">;

export function CardAction({ className, ...props }: CardActionProps) {
  return (
    <div
      data-slot="card-action"
      className={cn("col-start-2 row-span-2 row-start-1 self-start justify-self-end", className)}
      {...props}
    />
  );
}

import type { ComponentPropsWithRef } from "react";
import { cn } from "@/lib/utils";

export type CardHeaderProps = ComponentPropsWithRef<"div">;

export function CardHeader({ className, ...props }: CardHeaderProps) {
  return (
    <div
      data-slot="card-header"
      className={cn(
        "grid auto-rows-min grid-rows-[auto_auto] items-start gap-1.5 border-b border-border px-4 py-3 text-sm text-foreground has-data-[slot=card-action]:grid-cols-[1fr_auto]",
        className,
      )}
      {...props}
    />
  );
}

import type { ComponentPropsWithRef } from "react";
import { cn } from "@/lib/utils";

export type CardTitleProps = ComponentPropsWithRef<"h3"> & {
  as?: "h2" | "h3" | "h4" | "h5";
};

export function CardTitle({ as: Tag = "h3", className, ...props }: CardTitleProps) {
  return <Tag data-slot="card-title" className={cn("text-xl font-bold text-foreground tracking-wide", className)} {...props} />;
}

import type { ComponentPropsWithRef } from "react";
import { cn } from "@/lib/utils";

export type CardDescriptionProps = ComponentPropsWithRef<"p">;

export function CardDescription({ className, ...props }: CardDescriptionProps) {
  return <p data-slot="card-description" className={cn("text-sm text-muted-foreground", className)} {...props} />;
}

import type { ComponentPropsWithRef } from "react";
import { cn } from "@/lib/utils";

export type CardContentProps = ComponentPropsWithRef<"div">;

export function CardContent({ className, ...props }: CardContentProps) {
  return <div data-slot="card-content" className={cn("p-6", className)} {...props} />;
}

import type { ComponentPropsWithRef } from "react";
import { cva, type VariantProps } from "class-variance-authority";
import { cn } from "@/lib/utils";

export const cardLabelVariants = cva(
  "absolute -top-3 left-4 z-10 bg-background px-2 text-xs font-bold uppercase tracking-wider text-muted-foreground",
  {
    variants: {
      variant: {
        border: "border border-border",
        gap: "",
      },
    },
    defaultVariants: { variant: "border" },
  },
);

export type CardLabelProps = ComponentPropsWithRef<"div"> & VariantProps<typeof cardLabelVariants>;

export function CardLabel({ className, variant, ...props }: CardLabelProps) {
  return <div data-slot="card-label" className={cn(cardLabelVariants({ variant }), className)} {...props} />;
}

import type { ComponentPropsWithRef } from "react";
import { cn } from "@/lib/utils";

export type CardFooterProps = ComponentPropsWithRef<"div">;

export function CardFooter({ className, ...props }: CardFooterProps) {
  return (
    <div data-slot="card-footer" className={cn("flex justify-end gap-3 border-t border-border bg-background/50 px-6 py-4", className)} {...props} />
  );
}
